def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            weight = (8 - j) / 28
            term = ratio ** j
            if j % 3 == 0:
                term *= (1 + 0.15 * j)
            elif j % 2 == 0:
                term *= (1 + 0.1 * j)
            else:
                term *= (1 - 0.07 * j)
            score += weight * term
        if capacity > 4 * item:
            score *= 0.3
        elif capacity > 3 * item:
            score *= 0.5
        elif capacity > 2 * item:
            score *= 0.7
        elif capacity > 1.5 * item:
            score *= 0.9
        else:
            score *= 1.3
        if capacity < 1.1 * item:
            score *= 1.7
        elif capacity < 1.3 * item:
            score *= 1.3
        elif capacity < 1.5 * item:
            score *= 1.1
        diff = capacity - item
        if diff > 0:
            for k in range(1, 6):
                decay = np.exp(-diff * k * 0.5)
                score += (0.04 / k) * decay
                if k % 2 == 0:
                    score += 0.01 * decay * k
        else:
            for k in range(1, 6):
                growth = np.exp(diff * k * 0.7)
                score += (0.12 * k) * growth
                if k == 3:
                    score += 0.2 * growth
        if ratio > 0.8 and ratio < 1:
            score *= 0.85
        elif ratio > 0.5 and ratio <= 0.8:
            score *= 0.95
        else:
            score *= 1.1
        if capacity % 2 == 0:
            score *= 0.97
        else:
            score *= 1.03
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 15
    min_p = np.min(priorities)
    max_p = np.max(priorities)
    if max_p != min_p:
        priorities = (priorities - min_p) / (max_p - min_p)
    else:
        priorities = np.zeros_like(priorities)
    return priorities
